
.manager-backdrop {
  position: fixed;
  z-index: 10000;
  inset: 0;
  display: grid;
  place-items: center;
  padding: 18px;
  background: rgba(2, 2, 4, 0.82);
  backdrop-filter: blur(5px);
}

.manager-panel {
  display: flex;
  width: min(960px, 96vw);
  height: min(720px, 92vh);
  min-height: 420px;
  flex-direction: column;
  overflow: hidden;
  border: 1px solid rgba(207, 200, 184, 0.24);
  border-radius: 8px;
  background:
    radial-gradient(circle at 85% 0%, rgba(126, 36, 36, 0.16), transparent 36%),
    linear-gradient(145deg, rgba(18, 16, 20, 0.99), rgba(6, 5, 8, 0.99));
  box-shadow: 0 24px 70px rgba(0, 0, 0, 0.8), inset 0 0 50px rgba(0, 0, 0, 0.35);
  color: var(--c-text);
}

.manager-header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 20px;
  padding: 18px 22px 15px;
  border-bottom: 1px solid rgba(207, 200, 184, 0.13);
}

.manager-kicker {
  margin: 0 0 3px;
  color: var(--c-accent-bright);
  font-size: 0.54rem;
  letter-spacing: 0.26em;
}

.manager-header h2 {
  margin: 0;
  font-family: var(--font-brush);
  font-size: 1.22rem;
  font-weight: 400;
  letter-spacing: 0.16em;
}

.manager-header p:not(.manager-kicker) {
  margin: 5px 0 0;
  color: var(--c-text-dim);
  font-size: 0.7rem;
}

.manager-header code { color: #d8bd91; }

.icon-button {
  display: grid;
  width: 34px;
  height: 34px;
  flex: 0 0 auto;
  place-items: center;
  border: 1px solid rgba(207, 200, 184, 0.18);
  border-radius: 4px;
  background: rgba(0, 0, 0, 0.22);
  color: var(--c-text-dim);
  cursor: pointer;
}

.icon-button:hover { border-color: var(--c-accent-bright); color: var(--c-accent-bright); }

.manager-toolbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  padding: 10px 14px;
  border-bottom: 1px solid rgba(207, 200, 184, 0.09);
  background: rgba(0, 0, 0, 0.2);
}

.mode-switch { display: flex; gap: 5px; }

.mode-switch button,
.reload-button {
  padding: 7px 10px;
  border: 1px solid rgba(207, 200, 184, 0.14);
  border-radius: 3px;
  background: transparent;
  color: var(--c-text-dim);
  font-size: 0.68rem;
  cursor: pointer;
}

.mode-switch button.active {
  border-color: rgba(198, 69, 69, 0.52);
  background: rgba(168, 51, 51, 0.14);
  color: var(--c-text);
}

.mode-switch i,
.reload-button i { margin-right: 4px; }
.reload-button:hover { color: var(--c-text); }

.manager-workspace {
  display: grid;
  min-height: 0;
  flex: 1;
  grid-template-columns: 175px minmax(0, 1fr);
}

.category-nav {
  overflow-y: auto;
  padding: 8px;
  border-right: 1px solid rgba(207, 200, 184, 0.1);
  background: rgba(0, 0, 0, 0.18);
}

.category-nav button {
  display: flex;
  width: 100%;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
  padding: 9px 10px;
  border: 0;
  border-radius: 3px;
  background: transparent;
  color: var(--c-text-dim);
  font: 0.72rem var(--font-serif);
  text-align: left;
  cursor: pointer;
}

.category-nav button:hover { background: rgba(207, 200, 184, 0.05); color: var(--c-text); }
.category-nav button.active { background: rgba(168, 51, 51, 0.16); color: #ead9bf; }
.category-nav i { font-size: 0.55rem; opacity: 0.55; }

.tree-editor {
  min-width: 0;
  overflow-y: auto;
  padding: 12px;
}

.json-editor-wrap {
  display: flex;
  min-height: 0;
  flex: 1;
  flex-direction: column;
  gap: 8px;
  padding: 12px;
}

.json-warning {
  padding: 8px 10px;
  border: 1px solid rgba(201, 169, 78, 0.2);
  border-radius: 3px;
  background: rgba(201, 169, 78, 0.06);
  color: #c9b789;
  font-size: 0.68rem;
}

.json-warning i { margin-right: 5px; }

.json-editor {
  width: 100%;
  min-height: 0;
  flex: 1;
  box-sizing: border-box;
  padding: 13px;
  resize: none;
  border: 1px solid rgba(207, 200, 184, 0.17);
  border-radius: 4px;
  outline: none;
  background: rgba(0, 0, 0, 0.43);
  color: #d8d1c4;
  font: 0.72rem/1.55 Consolas, Monaco, monospace;
  tab-size: 2;
}

.json-editor:focus { border-color: rgba(198, 69, 69, 0.62); }

.validation-box {
  max-height: 132px;
  overflow-y: auto;
  padding: 9px 14px;
  border-top: 1px solid rgba(210, 70, 70, 0.22);
  background: rgba(120, 20, 20, 0.15);
  color: #e6b7ac;
  font-size: 0.67rem;
}

.validation-box ul { margin: 6px 0 0; padding-left: 20px; }
.validation-box p { margin: 5px 0 0; }

.manager-footer {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 14px;
  padding: 11px 14px;
  border-top: 1px solid rgba(207, 200, 184, 0.13);
  background: rgba(0, 0, 0, 0.28);
}

.dirty-state {
  color: #87aa8a;
  font-size: 0.68rem;
}

.dirty-state.dirty { color: #d1ad72; }
.dirty-state i { width: 16px; }
.footer-actions { display: flex; gap: 8px; }

.cancel-button,
.save-button {
  min-width: 88px;
  padding: 8px 12px;
  border-radius: 3px;
  font-size: 0.7rem;
  cursor: pointer;
}

.cancel-button {
  border: 1px solid rgba(207, 200, 184, 0.16);
  background: transparent;
  color: var(--c-text-dim);
}

.save-button {
  border: 1px solid rgba(198, 69, 69, 0.55);
  background: rgba(138, 36, 36, 0.3);
  color: #ead9bf;
}

.save-button i { margin-right: 4px; }
.save-button:disabled { cursor: not-allowed; opacity: 0.4; }
.save-button:not(:disabled):hover { background: rgba(168, 51, 51, 0.42); }

.manager-fade-enter-active,
.manager-fade-leave-active { transition: opacity 0.18s ease; }
.manager-fade-enter-active .manager-panel,
.manager-fade-leave-active .manager-panel { transition: transform 0.22s cubic-bezier(.22,.61,.36,1); }
.manager-fade-enter-from,
.manager-fade-leave-to { opacity: 0; }
.manager-fade-enter-from .manager-panel { transform: translateY(8px) scale(0.99); }
.manager-fade-leave-to .manager-panel { transform: translateY(5px) scale(0.995); }

@media (max-width: 620px) {
  .manager-backdrop { padding: 6px; }
  .manager-panel { width: 100%; height: 96vh; min-height: 0; }
  .manager-header { padding: 13px 14px 11px; }
  .manager-header p:not(.manager-kicker) { display: none; }
  .manager-workspace { grid-template-columns: 112px minmax(0, 1fr); }
  .category-nav { padding: 5px; }
  .category-nav button { padding: 8px 6px; font-size: 0.64rem; }
  .tree-editor { padding: 7px; }
  .dirty-state { display: none; }
  .manager-footer { justify-content: flex-end; }
}
