
.combat-panel-shell {
  position: relative;
  padding: 12px 16px 14px;
  background:
    linear-gradient(135deg, rgba(83, 22, 29, 0.2), transparent 42%), linear-gradient(180deg, #09080b, #050507);
  border-top: 1px solid rgba(164, 64, 70, 0.42);
  border-bottom: 1px solid rgba(164, 64, 70, 0.28);
  color: var(--c-text);
  font-family: var(--font-ui);
}

.combat-head,
.combat-title,
.momentum-row,
.combatant-top,
.combatant-meta,
.opportunities {
  display: flex;
  align-items: center;
}

.combat-head {
  justify-content: space-between;
  gap: 12px;
}

.combat-title {
  gap: 10px;
  min-width: 0;

  p,
  h3 {
    margin: 0;
  }

  p {
    color: #b96b70;
    font-size: 0.62rem;
    letter-spacing: 0.16em;
  }

  h3 {
    margin-top: 2px;
    color: #ddd5c6;
    font-family: var(--font-serif);
    font-size: 0.9rem;
    font-weight: 500;
    letter-spacing: 0.08em;
    overflow-wrap: anywhere;
  }
}

.combat-seal {
  display: grid;
  place-items: center;
  width: 30px;
  height: 30px;
  border: 1px solid #a44046;
  color: #d17c81;
  font-family: var(--font-serif);
  box-shadow:
    inset 0 0 10px rgba(164, 64, 70, 0.22),
    0 0 12px rgba(164, 64, 70, 0.14);
  transform: rotate(-3deg);
  flex: 0 0 auto;
}

.stakes {
  max-width: 44%;
  color: #8f8378;
  font-size: 0.64rem;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.momentum-row {
  gap: 8px;
  margin-top: 11px;
}

.side-label,
.momentum-value {
  font-size: 0.58rem;
  letter-spacing: 0.1em;
}

.side-label.enemy {
  color: #a6565c;
}
.side-label.ally {
  color: #8ba1aa;
}
.momentum-value {
  width: 22px;
  text-align: center;
  color: #d6cbb9;
}

.momentum-track {
  display: grid;
  grid-template-columns: repeat(7, 1fr);
  align-items: center;
  gap: 4px;
  flex: 1;
  height: 12px;
  background: linear-gradient(90deg, rgba(164, 64, 70, 0.2), rgba(120, 112, 100, 0.08), rgba(69, 101, 114, 0.2));
  padding: 0 5px;
  border-radius: 999px;
}

.momentum-node {
  height: 3px;
  border-radius: 999px;
  background: #302d2d;

  &.passed {
    background: #776864;
  }
  &.active {
    height: 8px;
    background: #d0b28e;
    box-shadow: 0 0 8px rgba(208, 178, 142, 0.62);
  }
}

.intent-card {
  display: grid;
  grid-template-columns: auto 1fr;
  gap: 10px;
  align-items: start;
  margin-top: 10px;
  padding: 8px 10px;
  border-left: 2px solid #a44046;
  background: rgba(164, 64, 70, 0.08);

  p {
    margin: 0;
    color: #c9c0b3;
    font-size: 0.72rem;
    line-height: 1.55;
  }
}

.intent-label {
  color: #c06d72;
  font-size: 0.64rem;
  letter-spacing: 0.12em;
  white-space: nowrap;
}

.opportunities {
  flex-wrap: wrap;
  gap: 6px;
  margin-top: 8px;
}

.opportunity {
  padding: 3px 7px;
  border: 1px solid rgba(181, 157, 116, 0.28);
  color: #b9aa90;
  background: rgba(181, 157, 116, 0.06);
  font-size: 0.61rem;

  i {
    margin-right: 5px;
    font-size: 0.55rem;
  }
}

.combatants {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 8px;
  margin-top: 10px;
}

.combatant {
  padding: 8px 9px;
  border: 1px solid rgba(130, 120, 108, 0.2);
  background: rgba(255, 255, 255, 0.018);

  &.enemy {
    border-color: rgba(164, 64, 70, 0.3);
  }
  &.ally {
    border-color: rgba(69, 101, 114, 0.34);
  }
}

.combatant-top {
  justify-content: space-between;
  gap: 8px;
  margin-bottom: 6px;

  strong {
    color: #d7cfc1;
    font-size: 0.7rem;
    font-weight: 500;
  }
  span {
    color: #8d8378;
    font-size: 0.58rem;
  }
}

.mini-vital {
  height: 3px;
  margin-top: 3px;
  background: rgba(255, 255, 255, 0.055);

  span {
    display: block;
    height: 100%;
    transition: width 0.4s ease;
  }
  &.hp span {
    background: linear-gradient(90deg, #6a1f25, #b24b51);
  }
  &.mp span {
    background: linear-gradient(90deg, #263f4a, #547587);
  }
}

.combatant-meta {
  flex-wrap: wrap;
  gap: 4px 8px;
  margin-top: 6px;
  color: #766f68;
  font-size: 0.54rem;
}

.status-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 4px;
  margin-top: 5px;

  span {
    color: #a89175;
    font-size: 0.54rem;
  }
}

.last-ruling {
  margin: 9px 0 0;
  color: #8f877d;
  font-family: var(--font-serif);
  font-size: 0.66rem;
  line-height: 1.5;

  span {
    margin-right: 8px;
    color: #b06569;
    font-family: var(--font-ui);
    letter-spacing: 0.1em;
  }
}

@media (max-width: 520px) {
  .combat-panel-shell {
    padding: 10px 12px 12px;
  }
  .combat-head {
    align-items: flex-start;
  }
  .stakes {
    max-width: 34%;
  }
  .combatants {
    grid-template-columns: 1fr;
  }
}
