
.friendly-editor {
  display: grid;
  min-height: 0;
  flex: 1;
  grid-template-columns: 140px minmax(0, 1fr);
}

.friendly-tabs {
  overflow-y: auto;
  padding: 10px 7px;
  border-right: 1px solid rgba(207, 200, 184, 0.1);
  background: rgba(0, 0, 0, 0.18);
}

.friendly-tabs button {
  display: flex;
  width: 100%;
  align-items: center;
  gap: 9px;
  padding: 10px 9px;
  border: 0;
  border-radius: 4px;
  background: transparent;
  color: var(--c-text-dim);
  font: 0.72rem var(--font-ui);
  text-align: left;
  cursor: pointer;
}

.friendly-tabs button:hover {
  background: rgba(207, 200, 184, 0.05);
  color: var(--c-text);
}
.friendly-tabs button.active {
  background: rgba(168, 51, 51, 0.17);
  color: #ead9bf;
}
.friendly-tabs i {
  width: 16px;
  color: #b77b72;
  text-align: center;
}

.friendly-content {
  min-width: 0;
  overflow-y: auto;
  padding: 16px;
}

.section-heading {
  display: flex;
  align-items: center;
  gap: 12px;
  margin-bottom: 15px;
  padding-bottom: 12px;
  border-bottom: 1px solid rgba(207, 200, 184, 0.1);
}

.section-icon {
  display: grid;
  width: 38px;
  height: 38px;
  flex: 0 0 auto;
  place-items: center;
  border: 1px solid rgba(198, 69, 69, 0.35);
  border-radius: 50%;
  background: rgba(168, 51, 51, 0.1);
  color: #d49283;
}

.section-heading h3 {
  margin: 0 0 3px;
  color: var(--c-text);
  font: 1rem var(--font-brush);
  letter-spacing: 0.12em;
}

.section-heading p {
  margin: 0;
  color: var(--c-text-dim);
  font-size: 0.68rem;
  line-height: 1.5;
}

.field-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 10px;
}

:deep(.friendly-field) {
  display: flex;
  min-width: 0;
  flex-direction: column;
  gap: 6px;
  padding: 10px;
  border: 1px solid rgba(207, 200, 184, 0.12);
  border-radius: 4px;
  background: rgba(6, 5, 8, 0.38);
}

:deep(.friendly-field.wide) {
  grid-column: 1 / -1;
}
:deep(.friendly-field-label) {
  color: #d5cbbb;
  font-size: 0.72rem;
}

:deep(.friendly-field input),
:deep(.friendly-field select),
:deep(.friendly-field textarea),
.record-toolbar select {
  width: 100%;
  box-sizing: border-box;
  padding: 8px 9px;
  border: 1px solid rgba(207, 200, 184, 0.18);
  border-radius: 3px;
  outline: none;
  background: rgba(0, 0, 0, 0.34);
  color: var(--c-text);
  font: 0.78rem var(--font-ui);
}

:deep(.friendly-field textarea) {
  min-height: 78px;
  resize: vertical;
  line-height: 1.5;
}
:deep(.friendly-field input:focus),
:deep(.friendly-field select:focus),
:deep(.friendly-field textarea:focus) {
  border-color: rgba(198, 69, 69, 0.7);
  box-shadow: 0 0 0 2px rgba(168, 51, 51, 0.1);
}
:deep(.friendly-field small) {
  color: var(--c-text-dim);
  font-size: 0.61rem;
  line-height: 1.4;
}

:deep(.friendly-boolean) {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 6px;
}

:deep(.friendly-boolean button) {
  padding: 8px;
  border: 1px solid rgba(207, 200, 184, 0.16);
  border-radius: 3px;
  background: rgba(0, 0, 0, 0.25);
  color: var(--c-text-dim);
  cursor: pointer;
}

:deep(.friendly-boolean button.active) {
  border-color: rgba(198, 69, 69, 0.58);
  background: rgba(168, 51, 51, 0.18);
  color: #ead9bf;
}

.record-toolbar {
  display: flex;
  align-items: flex-end;
  gap: 8px;
  margin-bottom: 12px;
  padding: 10px;
  border: 1px solid rgba(207, 200, 184, 0.1);
  border-radius: 4px;
  background: rgba(0, 0, 0, 0.2);
}

.record-toolbar label {
  display: flex;
  min-width: 120px;
  flex-direction: column;
  gap: 5px;
  color: var(--c-text-dim);
  font-size: 0.62rem;
}
.record-toolbar .record-select {
  min-width: 150px;
  flex: 1;
}

.record-action {
  height: 34px;
  flex: 0 0 auto;
  padding: 0 10px;
  border: 1px solid rgba(207, 200, 184, 0.16);
  border-radius: 3px;
  background: rgba(207, 200, 184, 0.04);
  color: var(--c-text-dim);
  font-size: 0.66rem;
  cursor: pointer;
}

.record-action.add {
  border-color: rgba(113, 151, 113, 0.35);
  color: #a9c1a5;
}
.record-action.remove {
  border-color: rgba(198, 69, 69, 0.3);
  color: #c98d84;
}
.record-action:disabled {
  cursor: not-allowed;
  opacity: 0.35;
}

.friendly-empty {
  display: grid;
  min-height: 180px;
  place-items: center;
  align-content: center;
  gap: 10px;
  color: var(--c-text-dim);
  text-align: center;
}

.friendly-empty i {
  font-size: 1.8rem;
  opacity: 0.4;
}
.friendly-empty p {
  margin: 0;
  font-size: 0.72rem;
}

@media (max-width: 620px) {
  .friendly-editor {
    grid-template-columns: 1fr;
    grid-template-rows: auto minmax(0, 1fr);
  }
  .friendly-tabs {
    display: flex;
    overflow-x: auto;
    padding: 5px;
    border-right: 0;
    border-bottom: 1px solid rgba(207, 200, 184, 0.1);
  }
  .friendly-tabs button {
    width: auto;
    flex: 0 0 auto;
    padding: 8px;
  }
  .friendly-tabs button span {
    white-space: nowrap;
  }
  .friendly-content {
    padding: 10px;
  }
  .field-grid {
    grid-template-columns: 1fr;
  }
  :deep(.friendly-field.wide) {
    grid-column: auto;
  }
  .record-toolbar {
    flex-wrap: wrap;
  }
  .record-toolbar label {
    min-width: calc(50% - 4px);
    flex: 1;
  }
  .record-action {
    flex: 1;
  }
}
