
.page-root {
  display: flex;
  flex-direction: column;
  height: 100%;
  position: relative;
  padding: 12px 18px 8px;
  overflow: hidden;
  gap: 10px;
  font-weight: 300;
}
.top-bar {
  display: flex;
  gap: 8px;
  flex-shrink: 0;
}
.top-card {
  flex: 1;
  display: flex;
  align-items: center;
  gap: 7px;
  padding: 7px 10px;
  border: 1px solid rgba(38, 38, 38, 0.5);
  background: rgba(0, 0, 0, 0.3);
}
.tc-icon {
  width: 30px;
  height: 30px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 2px;
  font-size: 0.75rem;
  flex-shrink: 0;
}
.enl .tc-icon {
  background: rgba(207, 200, 184, 0.15);
  color: var(--c-gold);
}
.org .tc-icon {
  background: rgba(168, 51, 51, 0.15);
  color: var(--c-stamp);
}
.rt .tc-icon {
  background: rgba(58, 95, 112, 0.15);
  color: var(--c-mp);
}
.tc-body {
  display: flex;
  flex-direction: column;
  gap: 1px;
}
.tc-label {
  font-size: 0.82rem;
  color: var(--c-text-dim);
  letter-spacing: 0.1em;
  font-weight: 300;
}
.tc-value {
  font-size: 1rem;
  font-weight: 400;
  color: var(--c-text);
  font-family: var(--font-serif);
  letter-spacing: 0.04em;
}

.learned-panel {
  flex: 1;
  min-height: 0;
  position: relative;
  display: flex;
  flex-direction: column;
  gap: 10px;
  padding: 10px 0 0;
  border-top: 1px solid rgba(38, 38, 38, 0.35);
}

.learned-head {
  display: flex;
  align-items: flex-end;
  justify-content: space-between;
  gap: 10px;
  flex-shrink: 0;
}
.learned-kicker {
  display: block;
  font-size: 0.55rem;
  color: var(--c-text-dim);
  letter-spacing: 0.2em;
  font-family: var(--font-serif);
  font-weight: 300;
}
.learned-head h2 {
  margin: 2px 0 0;
  font-size: 1.05rem;
  color: var(--c-text);
  font-family: var(--font-serif);
  letter-spacing: 0.12em;
  font-weight: 400;
}
.learned-count {
  color: var(--c-gold);
  font-size: 0.72rem;
  font-family: var(--font-serif);
  border: 1px solid rgba(207, 200, 184, 0.25);
  padding: 3px 9px;
  border-radius: 2px;
  background: rgba(0, 0, 0, 0.22);
  flex-shrink: 0;
}
.learned-empty {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  color: var(--c-text-dim);
  font-size: 0.82rem;
  font-family: var(--font-serif);
  font-style: italic;
  font-weight: 300;
  padding-bottom: 34px;
}

.learned-grid {
  flex: 1;
  min-height: 0;
  overflow-y: auto;
  overflow-x: hidden;
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(176px, 1fr));
  align-content: start;
  gap: 10px;
  padding: 0 4px 44px 0;
  scrollbar-width: thin;
  scrollbar-color: rgba(92, 92, 92, 0.3) transparent;
}
.learned-grid::-webkit-scrollbar {
  width: 4px;
}
.learned-grid::-webkit-scrollbar-track {
  background: transparent;
}
.learned-grid::-webkit-scrollbar-thumb {
  background: rgba(92, 92, 92, 0.3);
  border-radius: 2px;
}

.learned-card {
  min-height: 138px;
  padding: 10px 11px;
  border: 1px solid rgba(38, 38, 38, 0.45);
  border-radius: 2px;
  background:
    linear-gradient(180deg, rgba(14, 13, 15, 0.7), rgba(8, 7, 9, 0.86)),
    radial-gradient(circle at 85% 0%, rgba(207, 200, 184, 0.08), transparent 52%);
  cursor: pointer;
  transition:
    border-color 0.2s,
    background 0.2s,
    transform 0.2s;
  display: flex;
  flex-direction: column;
  gap: 7px;
}
.learned-card:hover {
  border-color: rgba(207, 200, 184, 0.4);
  background:
    linear-gradient(180deg, rgba(18, 16, 18, 0.78), rgba(10, 8, 10, 0.9)),
    radial-gradient(circle at 85% 0%, rgba(207, 200, 184, 0.12), transparent 52%);
  transform: translateY(-1px);
}
.lc-top,
.lc-meta {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
  color: var(--c-text-dim);
  font-size: 0.52rem;
  font-family: var(--font-serif);
  letter-spacing: 0.08em;
}
.lc-type {
  border: 1px solid currentColor;
  padding: 1px 5px;
  border-radius: 2px;
}
.lc-source {
  color: rgba(207, 200, 184, 0.45);
}
.learned-card h3 {
  margin: 0;
  color: var(--c-gold-light);
  font-size: 0.88rem;
  line-height: 1.3;
  font-family: var(--font-serif);
  letter-spacing: 0.06em;
  font-weight: 400;
}
.lc-effect {
  margin: 0;
  color: var(--c-text);
  font-size: 0.68rem;
  line-height: 1.55;
  font-family: var(--font-serif);
  font-weight: 300;
  display: -webkit-box;
  -webkit-line-clamp: 3;
  -webkit-box-orient: vertical;
  overflow: hidden;
}
.lc-bonus {
  margin-top: auto;
  color: var(--c-gold);
  font-size: 0.6rem;
  line-height: 1.35;
  font-family: var(--font-serif);
  border-top: 1px solid rgba(38, 38, 38, 0.45);
  padding-top: 6px;
}

.tree-fab {
  position: absolute;
  right: 2px;
  bottom: 2px;
  height: 32px;
  min-width: 98px;
  padding: 0 10px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  border: 1px solid rgba(90, 138, 159, 0.46);
  border-radius: 2px;
  background:
    linear-gradient(180deg, rgba(18, 28, 32, 0.88), rgba(8, 10, 12, 0.88)),
    radial-gradient(circle at 12% 50%, rgba(90, 138, 159, 0.24), transparent 58%);
  color: #8fc6d4;
  box-shadow:
    0 5px 14px rgba(0, 0, 0, 0.42),
    0 0 12px rgba(90, 138, 159, 0.12),
    inset 0 1px 0 rgba(207, 200, 184, 0.08);
  cursor: pointer;
  font-family: var(--font-serif);
  font-size: 0.64rem;
  letter-spacing: 0.08em;
  z-index: 4;
  transition:
    border-color 0.2s,
    color 0.2s,
    background 0.2s,
    transform 0.2s;
}
.tree-fab i {
  font-size: 0.7rem;
  color: #9ed0db;
  filter: drop-shadow(0 0 4px rgba(90, 138, 159, 0.45));
}
.tree-fab small {
  font-size: 0.5rem;
  color: rgba(207, 200, 184, 0.62);
  letter-spacing: 0;
}
.tree-fab:hover {
  color: var(--c-gold-light);
  border-color: rgba(207, 200, 184, 0.48);
  background:
    linear-gradient(180deg, rgba(22, 34, 38, 0.95), rgba(10, 12, 14, 0.94)),
    radial-gradient(circle at 12% 50%, rgba(207, 200, 184, 0.18), transparent 58%);
  transform: translateY(-1px);
}

.tree-page-bg {
  position: absolute;
  inset: 0;
  z-index: 45;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 0;
  background: radial-gradient(circle at 50% 44%, rgba(207, 200, 184, 0.08), transparent 45%), rgba(0, 0, 0, 0.82);
  backdrop-filter: blur(5px);
}
.tree-page {
  width: 100%;
  height: 100%;
  min-height: 0;
  display: flex;
  flex-direction: column;
  background:
    linear-gradient(180deg, rgba(16, 14, 16, 0.96), rgba(8, 7, 8, 0.98)),
    radial-gradient(circle at 50% 0%, rgba(207, 200, 184, 0.08), transparent 48%);
  border: 1px solid rgba(207, 200, 184, 0.28);
  outline: 1px solid rgba(0, 0, 0, 0.75);
  box-shadow:
    0 18px 44px rgba(0, 0, 0, 0.82),
    inset 0 0 0 1px rgba(207, 200, 184, 0.06);
  position: relative;
  overflow: hidden;
}
.tree-page::before {
  content: '';
  position: absolute;
  inset: 6px;
  border: 1px solid rgba(207, 200, 184, 0.08);
  pointer-events: none;
  z-index: 2;
}
.tree-page-head {
  height: 46px;
  flex-shrink: 0;
  display: grid;
  grid-template-columns: auto 1fr auto;
  align-items: center;
  gap: 10px;
  padding: 8px 12px;
  border-bottom: 1px solid rgba(207, 200, 184, 0.14);
  background: linear-gradient(90deg, rgba(0, 0, 0, 0.55), rgba(20, 17, 18, 0.62), rgba(0, 0, 0, 0.55));
  position: relative;
  z-index: 3;
}
.back-btn,
.advance-btn {
  height: 30px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  border-radius: 2px;
  font-family: var(--font-serif);
  font-size: 0.68rem;
  letter-spacing: 0.08em;
  cursor: pointer;
  transition:
    background 0.2s,
    border-color 0.2s,
    color 0.2s;
}
.back-btn {
  padding: 0 10px;
  border: 1px solid rgba(207, 200, 184, 0.22);
  background: rgba(0, 0, 0, 0.3);
  color: var(--c-text-dim);
}
.back-btn:hover {
  color: var(--c-gold);
  border-color: rgba(207, 200, 184, 0.42);
}
.advance-btn {
  padding: 0 12px;
  border: 1px solid rgba(207, 200, 184, 0.34);
  background: linear-gradient(180deg, rgba(207, 200, 184, 0.14), rgba(168, 51, 51, 0.08));
  color: var(--c-gold);
}
.advance-btn i {
  font-size: 0.78rem;
}
.advance-btn:hover:not(:disabled) {
  background: linear-gradient(180deg, rgba(207, 200, 184, 0.22), rgba(168, 51, 51, 0.12));
  border-color: var(--c-gold);
}
.advance-btn:disabled {
  opacity: 0.55;
  cursor: wait;
}
.tree-title {
  min-width: 0;
  text-align: center;
  font-family: var(--font-serif);
}
.tree-title span {
  display: block;
  color: var(--c-text);
  font-size: 0.92rem;
  letter-spacing: 0.16em;
}
.tree-title small {
  display: block;
  margin-top: 1px;
  color: var(--c-text-dim);
  font-size: 0.48rem;
  letter-spacing: 0.08em;
}

.tree-wrap {
  flex: 1;
  min-height: 0;
  display: flex;
  flex-direction: column;
}
.tree-canvas {
  flex: 1;
  min-height: 260px;
  border: 1px solid rgba(38, 38, 38, 0.3);
  background:
    radial-gradient(circle at 30% 30%, rgba(90, 138, 159, 0.08) 0%, transparent 45%),
    radial-gradient(circle at 70% 70%, rgba(207, 200, 184, 0.08) 0%, transparent 45%),
    radial-gradient(circle at center, rgba(207, 200, 184, 0.08) 0%, rgba(0, 0, 0, 0.2) 60%), #1a1a1a;
  overflow: hidden;
  position: relative;
  border-radius: var(--radius-sm);
  user-select: none;
  touch-action: none;
  -webkit-user-select: none;
}
.tree-world {
  position: relative;
}
.tw-svg {
  position: absolute;
  top: 0;
  left: 0;
  pointer-events: none;
  z-index: 1;
}

.t-node {
  position: absolute;
  width: 92px;
  z-index: 10;
  cursor: pointer;
  transition:
    transform 0.18s var(--ease-out-soft),
    filter 0.18s;
  will-change: transform;
}
.t-node:hover {
  z-index: 20;
  transform: scale(1.06);
  filter: brightness(1.2);
}
.tn-name {
  display: flex;
  min-height: 72px;
  box-sizing: border-box;
  flex-direction: column;
  font-size: 0.6rem;
  text-align: center;
  color: var(--c-text);
  padding: 5px 7px 6px;
  font-family: var(--font-serif);
  letter-spacing: 0.06em;
  line-height: 1.25;
  border: 1px solid rgba(207, 200, 184, 0.32);
  border-radius: var(--radius-sm);
  background:
    linear-gradient(180deg, rgba(22, 20, 25, 0.88) 0%, rgba(14, 12, 16, 0.95) 100%),
    radial-gradient(ellipse at 50% 0%, rgba(207, 200, 184, 0.08) 0%, transparent 70%);
  font-weight: 400;
  position: relative;
  box-shadow:
    inset 0 1px 0 rgba(207, 200, 184, 0.06),
    0 2px 6px rgba(0, 0, 0, 0.4);
}
.tn-meta {
  display: flex;
  align-items: center;
  justify-content: space-between;
  min-height: 13px;
  gap: 4px;
  padding-bottom: 4px;
  border-bottom: 1px solid rgba(207, 200, 184, 0.12);
}
.tn-title {
  display: flex;
  flex: 1;
  align-items: center;
  justify-content: center;
  min-height: 28px;
  padding: 4px 1px 3px;
  overflow-wrap: anywhere;
}
.t-node.can-learn .tn-name {
  border-color: rgba(106, 158, 179, 0.62);
  color: #91c8d6;
  background:
    linear-gradient(180deg, rgba(17, 27, 32, 0.94) 0%, rgba(10, 16, 19, 0.98) 100%),
    radial-gradient(ellipse at 50% 0%, rgba(106, 158, 179, 0.18) 0%, transparent 62%);
  box-shadow:
    inset 0 1px 0 rgba(139, 188, 205, 0.12),
    0 0 12px rgba(90, 138, 159, 0.1),
    0 2px 6px rgba(0, 0, 0, 0.4);
  animation: nodeBreathe 3s ease-in-out infinite;
}
.t-node.learned .tn-name {
  border-color: rgba(207, 200, 184, 0.55);
  color: var(--c-gold-light);
  background:
    linear-gradient(180deg, rgba(30, 26, 18, 0.9) 0%, rgba(18, 14, 8, 0.96) 100%),
    radial-gradient(ellipse at 50% 0%, rgba(207, 200, 184, 0.14) 0%, transparent 60%);
  box-shadow:
    inset 0 1px 0 rgba(207, 200, 184, 0.12),
    0 0 14px rgba(207, 200, 184, 0.12),
    0 2px 6px rgba(0, 0, 0, 0.5);
}
.t-node.locked .tn-name {
  border-color: rgba(92, 111, 119, 0.42);
  background:
    linear-gradient(180deg, rgba(18, 22, 25, 0.84), rgba(9, 11, 13, 0.93)),
    radial-gradient(ellipse at 50% 0%, rgba(92, 119, 130, 0.1), transparent 68%);
  color: rgba(184, 190, 194, 0.74);
  box-shadow:
    inset 0 1px 0 rgba(170, 184, 190, 0.06),
    0 2px 5px rgba(0, 0, 0, 0.32);
}
.t-node.locked {
  opacity: 0.76;
}
.t-node:hover .tn-name {
  border-color: rgba(207, 200, 184, 0.65);
}
.t-node.can-learn:hover .tn-name {
  border-color: rgba(90, 138, 159, 0.7);
  animation: none;
  box-shadow:
    inset 0 1px 0 rgba(90, 138, 159, 0.15),
    0 0 18px rgba(90, 138, 159, 0.16),
    0 3px 10px rgba(0, 0, 0, 0.5);
}
.t-node.learned:hover .tn-name {
  box-shadow:
    inset 0 1px 0 rgba(207, 200, 184, 0.18),
    0 0 20px rgba(207, 200, 184, 0.2),
    0 3px 10px rgba(0, 0, 0, 0.5);
}
@keyframes nodeBreathe {
  0%,
  100% {
    box-shadow:
      inset 0 1px 0 rgba(90, 138, 159, 0.08),
      0 0 10px rgba(90, 138, 159, 0.06),
      0 2px 6px rgba(0, 0, 0, 0.4);
  }
  50% {
    box-shadow:
      inset 0 1px 0 rgba(90, 138, 159, 0.12),
      0 0 16px rgba(90, 138, 159, 0.12),
      0 2px 6px rgba(0, 0, 0, 0.4);
  }
}
.tn-cost {
  display: block;
  font-size: 0.4rem;
  text-align: center;
  color: var(--c-gold-dim);
  min-height: 11px;
  padding-top: 3px;
  border-top: 1px solid rgba(207, 200, 184, 0.1);
  font-weight: 300;
  letter-spacing: 0.05em;
}
.t-node.can-learn .tn-cost {
  color: rgba(122, 184, 200, 0.65);
}
.t-node.locked .tn-cost {
  color: rgba(156, 166, 170, 0.62);
  opacity: 0.72;
}
.tn-type {
  font-size: 0.38rem;
  line-height: 1;
  font-weight: 400;
  white-space: nowrap;
}
.tp-a {
  color: #c4785e;
}
.tp-p {
  color: #6a9aaa;
}
.tn-lv {
  font-size: 0.36rem;
  color: var(--c-text-dim);
  opacity: 0.6;
  font-weight: 300;
  white-space: nowrap;
}
.t-node.learned .tn-lv {
  color: var(--c-gold);
  opacity: 0.85;
}
.t-node.can-learn .tn-lv {
  color: rgba(122, 184, 200, 0.55);
}
.tree-hint {
  text-align: center;
  font-size: 0.5rem;
  color: var(--c-text-dim);
  opacity: 0.35;
  padding: 2px 0 0;
  flex-shrink: 0;
  font-weight: 300;
}
.empty {
  display: flex;
  align-items: center;
  justify-content: center;
  height: 100%;
  color: var(--c-text-dim);
  font-family: var(--font-serif);
  font-size: 0.85rem;
  font-weight: 300;
}

.dlg-bg {
  position: absolute;
  inset: 0;
  background: rgba(0, 0, 0, 0.88);
  z-index: 50;
  display: flex;
  align-items: center;
  justify-content: center;
  backdrop-filter: blur(4px);
}
.dlg {
  width: 340px;
  background: var(--c-panel);
  border: 1px solid rgba(38, 38, 38, 0.5);
  box-shadow: 0 0 40px rgba(0, 0, 0, 0.8);
  position: relative;
  animation: mi 0.18s ease;
  font-weight: 300;
}
@keyframes mi {
  from {
    opacity: 0;
    transform: scale(0.95);
  }
  to {
    opacity: 1;
    transform: scale(1);
  }
}
.dlg-x {
  position: absolute;
  top: 7px;
  right: 9px;
  background: none;
  border: none;
  color: var(--c-text-dim);
  font-size: 1.1rem;
  cursor: pointer;
}
.dlg-x:hover {
  color: var(--c-gold);
}
.dlg-h {
  padding: 11px 14px;
  border-bottom: 1px solid rgba(38, 38, 38, 0.5);
  background: rgba(0, 0, 0, 0.4);
  font-size: 0.9rem;
  font-family: var(--font-serif);
  color: var(--c-text);
  letter-spacing: 0.08em;
  font-weight: 400;
}
.dlg-b {
  padding: 11px 14px;
  display: flex;
  flex-direction: column;
  gap: 6px;
}
.dr {
  display: flex;
  justify-content: space-between;
  font-size: 0.72rem;
  padding: 2px 0;
  font-weight: 300;
}
.dl {
  color: var(--c-text-dim);
}
.dv2 {
  color: var(--c-text);
  text-align: right;
}
.gd {
  color: var(--c-gold);
}
.dd2 {
  font-size: 0.7rem;
  color: var(--c-text-dim);
  line-height: 1.45;
  padding: 6px 0;
  border-top: 1px solid rgba(38, 38, 38, 0.3);
  font-weight: 300;
}
.bl {
  width: 100%;
  padding: 7px;
  margin-top: 5px;
  border: 1px solid var(--c-gold);
  background: rgba(207, 200, 184, 0.12);
  color: var(--c-gold);
  font-family: var(--font-serif);
  font-size: 0.78rem;
  letter-spacing: 0.08em;
  cursor: pointer;
  font-weight: 400;
}
.bl:hover {
  background: rgba(207, 200, 184, 0.22);
}
.bx {
  text-align: center;
  padding: 8px;
  color: var(--c-text-dim);
  font-size: 0.7rem;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 5px;
  border: 1px solid rgba(38, 38, 38, 0.3);
  margin-top: 5px;
  font-weight: 300;
}
.by {
  text-align: center;
  padding: 8px;
  color: var(--c-gold);
  font-size: 0.78rem;
  border: 1px solid rgba(207, 200, 184, 0.3);
  margin-top: 5px;
  font-family: var(--font-serif);
  font-weight: 400;
}

/* ===== 手机端适配 ===== */
@media (max-width: 500px) {
  .page-root {
    padding: 8px 10px 6px;
    gap: 8px;
  }
  .top-bar {
    gap: 5px;
  }
  .top-card {
    padding: 5px 6px;
    gap: 5px;
  }
  .tc-icon {
    width: 24px;
    height: 24px;
    font-size: 0.65rem;
  }
  .tc-label {
    font-size: 0.68rem;
  }
  .tc-value {
    font-size: 0.82rem;
  }
  .learned-panel {
    gap: 8px;
    padding-top: 8px;
  }
  .learned-head h2 {
    font-size: 0.92rem;
  }
  .learned-count {
    font-size: 0.64rem;
    padding: 2px 7px;
  }
  .learned-grid {
    grid-template-columns: 1fr;
    gap: 8px;
    padding: 0 2px 40px 0;
  }
  .learned-card {
    min-height: 116px;
    padding: 9px 10px;
  }
  .learned-card h3 {
    font-size: 0.82rem;
  }
  .lc-effect {
    font-size: 0.64rem;
    -webkit-line-clamp: 2;
  }
  .tree-fab {
    right: 1px;
    bottom: 1px;
    height: 29px;
    min-width: 84px;
    padding: 0 8px;
    font-size: 0.56rem;
  }
  .tree-fab small {
    display: none;
  }
  .tree-page-bg {
    padding: 0;
  }
  .tree-page {
    width: 100%;
    height: 100%;
  }
  .tree-page-head {
    height: 42px;
    gap: 6px;
    padding: 7px;
  }
  .back-btn,
  .advance-btn {
    height: 28px;
    gap: 4px;
    font-size: 0.6rem;
  }
  .back-btn {
    padding: 0 7px;
  }
  .advance-btn {
    padding: 0 8px;
  }
  .tree-title span {
    font-size: 0.8rem;
  }
  .tree-title small {
    font-size: 0.42rem;
  }
  .tree-canvas {
    min-height: 200px;
    border-radius: var(--radius-xs);
  }
  .t-node {
    width: 92px;
  }
  .tn-name {
    font-size: 0.58rem;
    padding: 5px 6px 6px;
  }
  .tn-cost {
    font-size: 0.38rem;
  }
  .tn-type {
    font-size: 0.36rem;
  }
  .tn-lv {
    font-size: 0.32rem;
  }
  .tree-hint {
    font-size: 0.45rem;
  }
  .dlg {
    width: auto;
    max-width: 92vw;
    margin: 0 12px;
  }
  .dlg-h {
    font-size: 0.82rem;
    padding: 9px 12px;
  }
  .dlg-b {
    padding: 9px 12px;
  }
  .dr {
    font-size: 0.65rem;
  }
  .dd2 {
    font-size: 0.62rem;
  }
  .bl,
  .by,
  .bx {
    font-size: 0.7rem;
  }
}

/* 触摸设备上禁用 hover 粘滞：通过 @media 精确匹配 */
@media (hover: none) {
  .t-node:hover {
    transform: none;
    filter: none;
  }
  .t-node:active {
    transform: scale(1.06);
    filter: brightness(1.15);
  }
}
