
.tree-group,
.tree-field {
  border: 1px solid rgba(207, 200, 184, 0.12);
  border-radius: 4px;
  background: rgba(8, 7, 10, 0.5);
}

.tree-group-root {
  border: 0;
  background: transparent;
}

.tree-group-header,
.tree-field-heading {
  display: flex;
  align-items: center;
  gap: 8px;
}

.tree-group-header { min-height: 38px; }

.tree-toggle {
  display: flex;
  flex: 1;
  align-items: center;
  gap: 8px;
  min-width: 0;
  padding: 9px 10px;
  border: 0;
  background: transparent;
  color: var(--c-text);
  text-align: left;
  cursor: pointer;
}

.tree-toggle i {
  width: 10px;
  color: var(--c-accent-bright);
  font-size: 0.62rem;
}

.tree-label {
  overflow: hidden;
  font-family: var(--font-serif);
  font-size: 0.86rem;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.tree-meta,
.tree-type {
  margin-left: auto;
  color: var(--c-text-dim);
  font-size: 0.62rem;
  white-space: nowrap;
}

.tree-remove {
  display: grid;
  width: 30px;
  height: 30px;
  flex: 0 0 auto;
  place-items: center;
  margin-right: 4px;
  border: 0;
  background: transparent;
  color: rgba(198, 69, 69, 0.65);
  cursor: pointer;
}

.tree-remove:hover { color: #ef7777; }

.tree-children {
  display: grid;
  gap: 7px;
  padding: 0 8px 8px 18px;
}

.tree-empty {
  padding: 12px;
  color: var(--c-text-dim);
  font-size: 0.72rem;
  text-align: center;
}

.tree-add-row {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  padding-top: 3px;
}

.tree-add-row button {
  padding: 5px 8px;
  border: 1px dashed rgba(207, 200, 184, 0.2);
  border-radius: 3px;
  background: rgba(207, 200, 184, 0.04);
  color: var(--c-text-dim);
  font-size: 0.66rem;
  cursor: pointer;
}

.tree-add-row button:hover {
  border-color: rgba(198, 69, 69, 0.5);
  color: var(--c-text);
}

.tree-field { padding: 9px 10px; }

.tree-field-heading {
  min-height: 22px;
  margin-bottom: 6px;
}

.tree-field-heading label {
  overflow-wrap: anywhere;
  color: var(--c-text-dim);
  font-size: 0.72rem;
}

.tree-field-heading .tree-remove {
  width: 24px;
  height: 24px;
  margin: 0 0 0 2px;
}

.value-input {
  width: 100%;
  box-sizing: border-box;
  padding: 7px 9px;
  border: 1px solid rgba(207, 200, 184, 0.18);
  border-radius: 3px;
  outline: none;
  background: rgba(0, 0, 0, 0.34);
  color: var(--c-text);
  font: 0.78rem/1.5 var(--font-ui);
}

.value-input:focus {
  border-color: rgba(198, 69, 69, 0.72);
  box-shadow: 0 0 0 2px rgba(168, 51, 51, 0.12);
}

.value-textarea {
  min-height: 74px;
  resize: vertical;
}

.boolean-editor {
  display: flex;
  align-items: center;
  gap: 8px;
  color: var(--c-text);
  font-size: 0.76rem;
  cursor: pointer;
}

.boolean-editor input { accent-color: var(--c-accent-bright); }

@media (max-width: 500px) {
  .tree-children { padding-left: 8px; }
  .tree-meta { display: none; }
}
