
/* ============ 全局过渡曲线 ============ */
$ease-out-soft: cubic-bezier(.22,.61,.36,1);
$ease-bounce:   cubic-bezier(.16,.84,.36,1.05);

/* ============ 黑色修士 · 水墨×黑暗 ============ */

.status-bar-root {
  width: 100%;
  max-width: 1040px;
  margin: 0 auto;
  position: relative;
  display: flex;
  justify-content: center;
  font-family: var(--font-ui);
  container-type: inline-size;

  &.collapsed .main-container {
    height: auto;
    aspect-ratio: unset;
    overflow: hidden;       /* 折叠时裁剪多余背景 */
  }
}

/* ===== 主容器：黑色磨砂底 ===== */
.main-container {
  position: relative;
  z-index: 1;
  width: 100%;
  display: flex;
  flex-direction: column;
  aspect-ratio: 4 / 3;       /* 高度跟随宽度，符合 iframe 适配规则 */
  max-width: 1040px;
  margin: 0 auto;

  /* 黑色磨砂背景 */
  background:
    /* 水墨噪点纹理 */
    url("data:image/svg+xml;utf8,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.85' numOctaves='3' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)' opacity='0.35'/%3E%3C/svg%3E") repeat,
    /* 暗角光晕 */
    radial-gradient(ellipse at 20% 0%, rgba(40, 30, 40, 0.45) 0%, transparent 50%),
    radial-gradient(ellipse at 100% 100%, rgba(80, 20, 20, 0.18) 0%, transparent 55%),
    /* 主底 */
    linear-gradient(145deg, rgba(15, 13, 18, 0.92), rgba(5, 4, 7, 0.97));
  background-size: 180px, cover, cover, cover;
  background-blend-mode: overlay, normal, normal, normal;

  border-radius: var(--radius-lg);
  box-shadow:
    inset 0 0 0 1px rgba(0, 0, 0, 0.7),
    inset 0 0 32px rgba(0, 0, 0, 0.65),
    inset 0 0 80px rgba(0, 0, 0, 0.4),
    0 12px 36px rgba(0, 0, 0, 0.75);
  color: var(--c-text);

  /* 让子内容覆盖在背景之上 */
  > * {
    position: relative;
    z-index: 1;
  }

  /* 顶部血色高光装饰带 */
  &::after {
    content: '';
    position: absolute;
    top: 0;
    left: 14%;
    right: 14%;
    height: 1px;
    background: linear-gradient(90deg,
      transparent,
      rgba(168, 51, 51, 0.45) 30%,
      rgba(207, 200, 184, 0.6) 50%,
      rgba(168, 51, 51, 0.45) 70%,
      transparent);
    pointer-events: none;
    z-index: 30;
  }
}

@media (max-width: 720px) {
  .status-bar-root { max-width: 100%; }
  .main-container { max-width: 100%; }
}

/* ===== Header ===== */
.app-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 28px;
  height: 76px;
  border-bottom: 1px solid rgba(207, 200, 184, 0.12);
  background:
    linear-gradient(to bottom,
      rgba(0, 0, 0, 0.5) 0%,
      transparent 100%);
  position: relative;
  z-index: 20;
  flex-shrink: 0;
}

.header-left {
  display: flex;
  align-items: center;
  gap: 18px;
  min-width: 0;
  flex: 0 0 auto;
}

.header-map-title {
  color: var(--c-text);
  font-family: var(--font-brush);
  letter-spacing: 0.4em;
  font-size: 1.1rem;
  text-shadow: 0 0 10px rgba(207, 200, 184, 0.3);

  /* 装饰两侧短线 */
  position: relative;
  padding: 0 1.4em;
  &::before, &::after {
    content: '';
    position: absolute;
    top: 50%;
    width: 14px;
    height: 1px;
    background: linear-gradient(90deg, transparent, var(--c-text-dim));
    transform: translateY(-50%);
  }
  &::before { left: 0; }
  &::after  { right: 0; background: linear-gradient(270deg, transparent, var(--c-text-dim)); }
}

/* ===== 子标签栏 ===== */
.sub-tabs {
  display: flex;
  flex: 1;
  justify-content: space-evenly;
  align-items: center;
  position: relative;
}

.sub-tab-btn {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
  padding: 4px 0;
  border: none;
  background: transparent;
  color: var(--c-text-dim);
  font-family: var(--font-brush);
  font-size: 0.82rem;
  font-weight: 400;
  letter-spacing: 0.18em;
  cursor: pointer;
  transition: color 0.3s $ease-out-soft, text-shadow 0.3s;
  position: relative;
  flex: 1;

  /* 按钮间竖线分隔 */
  &:not(:last-child)::after {
    content: '';
    position: absolute;
    right: 0;
    top: 15%;
    bottom: 15%;
    width: 1px;
    background: linear-gradient(to bottom,
      transparent,
      rgba(207, 200, 184, 0.18) 40%,
      rgba(207, 200, 184, 0.18) 60%,
      transparent);
    pointer-events: none;
  }

  &:hover {
    color: var(--c-text);
    .sub-tab-icon {
      opacity: 0.95;
      transform: translateY(-1px);
      filter: drop-shadow(0 0 4px rgba(207, 200, 184, 0.4));
    }
  }

  &.active {
    color: var(--c-text);
    text-shadow:
      0 0 10px rgba(168, 51, 51, 0.5),
      0 0 18px rgba(168, 51, 51, 0.3);
  }
}

.sub-tab-icon {
  font-size: 1.1rem;
  opacity: 0.55;
  transition: opacity 0.3s, transform 0.3s $ease-out-soft, filter 0.3s;

  &.active {
    opacity: 1;
    color: var(--c-accent-bright);
    filter: drop-shadow(0 0 8px rgba(198, 69, 69, 0.7));
  }
}

.sub-tab-indicator {
  position: absolute;
  bottom: -4px;
  left: 50%;
  transform: translateX(-50%);
  width: 32px;
  height: 3px;
  background: linear-gradient(90deg,
    transparent,
    var(--c-accent) 30%,
    var(--c-accent-bright) 50%,
    var(--c-accent) 70%,
    transparent);
  border-radius: var(--radius-pill);
  box-shadow:
    0 -2px 12px rgba(168, 51, 51, 0.8),
    0 0 8px rgba(168, 51, 51, 0.6);
  animation: indicator-in 0.35s $ease-bounce;
}

@keyframes indicator-in {
  from { transform: translateX(-50%) scaleX(0.2); opacity: 0; }
  to   { transform: translateX(-50%) scaleX(1);   opacity: 1; }
}

/* ===== 时间地点信息栏 ===== */
.info-bar {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0;
  padding: 10px 28px;
  border-bottom: 1px solid rgba(207, 200, 184, 0.08);
  background:
    linear-gradient(180deg,
      rgba(0, 0, 0, 0.35) 0%,
      rgba(0, 0, 0, 0.18) 100%);
  font-family: var(--font-ui);
  flex-shrink: 0;
  position: relative;

  /* 底部细分割线 */
  &::after {
    content: '';
    position: absolute;
    left: 25%;
    right: 25%;
    bottom: -1px;
    height: 1px;
    background: linear-gradient(90deg,
      transparent,
      rgba(207, 200, 184, 0.18) 50%,
      transparent);
  }
}

.info-item {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 0 22px;
  transition: opacity 0.25s;

  &:hover {
    opacity: 1;
    .info-icon {
      color: var(--c-accent-bright);
      filter: drop-shadow(0 0 6px rgba(198, 69, 69, 0.6));
    }
  }
}

.info-icon {
  font-size: 0.78rem;
  color: var(--c-text);
  opacity: 0.7;
  filter: drop-shadow(0 0 4px rgba(207, 200, 184, 0.3));
  transition: color 0.25s, filter 0.25s;
}

.info-label {
  font-size: 0.72rem;
  color: var(--c-text-dim);
  letter-spacing: 0.18em;
  font-weight: 300;
  font-family: var(--font-ui);
}

.info-value {
  font-size: 0.85rem;
  color: var(--c-text);
  font-family: var(--font-ui);
  letter-spacing: 0.08em;
  font-weight: 400;
  text-shadow: 0 1px 2px rgba(0, 0, 0, 0.5);
}

.info-sep {
  width: 1px;
  height: 18px;
  background: linear-gradient(to bottom,
    transparent,
    rgba(207, 200, 184, 0.25),
    transparent);
}

.info-actions {
  display: flex;
  flex: 0 0 auto;
  gap: 6px;
  margin-left: auto;
}

.collapse-toggle,
.variable-manager-toggle {
  background: rgba(0, 0, 0, 0.4);
  border: 1px solid rgba(207, 200, 184, 0.18);
  color: var(--c-text-dim);
  width: 28px;
  height: 28px;
  border-radius: var(--radius-sm);
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  transition: all 0.25s $ease-out-soft;
  font-size: 0.65rem;
  flex-shrink: 0;

  &:hover {
    border-color: var(--c-accent-bright);
    color: var(--c-accent-bright);
    background: rgba(168, 51, 51, 0.12);
    box-shadow:
      0 0 10px rgba(168, 51, 51, 0.35),
      inset 0 0 6px rgba(168, 51, 51, 0.15);
  }
  &:active { transform: scale(0.92); }
}

.variable-manager-toggle {
  color: rgba(207, 200, 184, 0.82);

  &:hover {
    border-color: rgba(201, 169, 78, 0.7);
    color: #d8bd91;
    background: rgba(201, 169, 78, 0.1);
    box-shadow: 0 0 10px rgba(201, 169, 78, 0.2);
  }
}

/* ===== 内容区域 ===== */
.content-area {
  flex: 1;
  overflow: hidden;
  position: relative;
  z-index: 10;
  background: transparent;
  min-height: 0;
  transition:
    height 0.3s $ease-out-soft,
    max-height 0.35s $ease-out-soft,
    opacity 0.22s ease;
  opacity: 1;

  &.collapsed {
    max-height: 0 !important;
    opacity: 0;
    flex: 0;
  }
}

.worldmap-active {
  .main-container {
    height: auto;
    aspect-ratio: unset;
  }

  .content-area {
    flex: 0 0 auto;
    height: calc(100cqw * 9 / 16);
    overflow: hidden;
  }
}

.adaptive-active {
  .main-container {
    height: auto;
    aspect-ratio: unset;
  }

  .content-area {
    flex: 0 0 auto;
    height: var(--adaptive-content-height, auto);
    overflow: hidden;
  }

  .content-area :deep(.page-root),
  .content-area :deep(.mijing-tab),
  .content-area :deep(.avatar-page) {
    height: auto;
    min-height: 0;
    box-sizing: border-box;
    overflow-y: visible;
  }

  .content-area :deep(.bond-panel),
  .content-area :deep(.learned-grid),
  .content-area :deep(.char-grid) {
    flex: 0 0 auto;
    min-height: 0;
    max-height: none;
    overflow-y: visible;
  }

  .content-area :deep(.mijing-empty),
  .content-area :deep(.locked-overlay) {
    min-height: 260px;
    box-sizing: border-box;
  }

  .content-area :deep(.shenqi-page),
  .content-area :deep(.techniques-page.tree-open) {
    height: var(--adaptive-content-height, auto);
    min-height: 0;
    overflow-y: auto;
  }

  .content-area :deep(.techniques-page.tree-open) {
    overflow: hidden;
  }
}

/* ===== 底部导航栏 ===== */
.bottom-nav {
  display: grid;
  grid-template-columns: 1fr 1fr 1fr;
  height: 74px;
  background:
    linear-gradient(to top,
      rgba(0, 0, 0, 0.6) 0%,
      rgba(0, 0, 0, 0.25) 100%);
  border-top: 1px solid rgba(207, 200, 184, 0.12);
  z-index: 20;
  flex-shrink: 0;
  position: relative;
}

.nav-btn {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 5px;
  border: none;
  background: transparent;
  color: var(--c-text);
  opacity: 0.5;
  font-family: var(--font-ui);
  font-size: 0.76rem;
  font-weight: 400;
  letter-spacing: 0.22em;
  cursor: pointer;
  transition: all 0.3s $ease-out-soft;
  position: relative;
  overflow: hidden;

  &:first-child {
    border-right: 1px solid rgba(207, 200, 184, 0.08);
  }
  &:nth-child(2) {
    border-right: 1px solid rgba(207, 200, 184, 0.08);
  }

  /* hover 时光晕从下涌起 */
  &::before {
    content: '';
    position: absolute;
    left: 0; right: 0; bottom: 0;
    height: 0;
    background: linear-gradient(to top,
      rgba(207, 200, 184, 0.1) 0%,
      transparent 100%);
    transition: height 0.35s $ease-out-soft;
    pointer-events: none;
  }

  &:hover {
    opacity: 0.9;
    .nav-btn-icon {
      transform: translateY(-2px);
      filter: drop-shadow(0 0 6px rgba(207, 200, 184, 0.4));
    }
    &::before { height: 100%; }
  }

  &.active {
    opacity: 1;
    color: var(--c-text);
    text-shadow:
      0 0 10px rgba(168, 51, 51, 0.5),
      0 0 18px rgba(168, 51, 51, 0.3);
    .nav-btn-icon {
      color: var(--c-accent-bright);
      filter: drop-shadow(0 0 8px rgba(198, 69, 69, 0.7));
    }
    &::before {
      height: 100%;
      background: linear-gradient(to top,
        rgba(168, 51, 51, 0.2) 0%,
        rgba(168, 51, 51, 0.05) 50%,
        transparent 100%);
    }
    &::after {
      content: '';
      position: absolute;
      bottom: 0;
      left: 50%;
      transform: translateX(-50%);
      width: 44%;
      height: 2px;
      background: linear-gradient(90deg,
        transparent,
        var(--c-accent-bright),
        transparent);
      box-shadow: 0 0 14px rgba(198, 69, 69, 0.8);
    }
  }
}

.nav-btn-mijing {
  &.highlight:not(.active) {
    opacity: 0.85;
    color: var(--c-accent-bright);
    .nav-btn-icon {
      color: var(--c-accent-bright);
      filter: drop-shadow(0 0 6px rgba(198, 69, 69, 0.55));
      animation: mijing-pulse 2.4s ease-in-out infinite;
    }
  }
  &:not(.highlight):not(.active) {
    opacity: 0.3;
  }
}

@keyframes mijing-pulse {
  0%, 100% { transform: translateY(0); }
  50%      { transform: translateY(-1px); }
}

.nav-btn-icon {
  font-size: 1.25rem;
  transition: transform 0.3s $ease-out-soft, filter 0.3s, color 0.3s;
}

/* ===== 版本标签 ===== */
.version-label {
  position: absolute;
  bottom: 0;
  right: 0;
  padding: 4px;
  font-size: 0.42rem;
  color: var(--c-text-dim);
  opacity: 0.18;
  pointer-events: none;
  z-index: 20;
  font-weight: 300;
  font-family: var(--font-ui);
  letter-spacing: 0.1em;
}

/* ===== 过渡 ===== */
.tab-fade-enter-active,
.tab-fade-leave-active {
  transition: opacity 0.18s ease, transform 0.22s $ease-out-soft;
  backface-visibility: hidden;
  will-change: opacity, transform;
}

.tab-fade-enter-active {
  position: relative;
  z-index: 1;
}

.tab-fade-leave-active {
  position: absolute;
  inset: 0;
  z-index: 0;
  width: 100%;
  pointer-events: none;
}

.tab-fade-enter-from { opacity: 0; transform: translate3d(0, 4px, 0); }
.tab-fade-leave-to   { opacity: 0; transform: translate3d(0, -3px, 0); }

@media (prefers-reduced-motion: reduce) {
  .content-area,
  .tab-fade-enter-active,
  .tab-fade-leave-active {
    transition-duration: 0.01ms;
  }
}

/* ===== 内容区美化滚动条（仅状态栏内部生效） ===== */
.content-area :deep(::-webkit-scrollbar)        { width: 6px; height: 6px; }
.content-area :deep(::-webkit-scrollbar-track)  { background: rgba(0,0,0,0.3); }
.content-area :deep(::-webkit-scrollbar-thumb)  {
  background: linear-gradient(180deg,
    rgba(207,200,184,0.2),
    rgba(207,200,184,0.3),
    rgba(207,200,184,0.2));
  border-radius: 3px;
  transition: background 0.25s, box-shadow 0.25s;
}
.content-area :deep(::-webkit-scrollbar-thumb:hover) {
  background: linear-gradient(180deg,
    rgba(168,51,51,0.5),
    rgba(198,69,69,0.7),
    rgba(168,51,51,0.5));
  box-shadow: 0 0 6px rgba(168,51,51,0.4);
}

/* ===== 手机端 ===== */
@media (max-width: 500px) {
  .app-header { height: 60px; padding: 0 8px; }
  .sub-tabs { gap: 0; }
  .sub-tab-btn { font-size: 0.68rem; }
  .sub-tab-icon { font-size: 0.85rem; }
  .sub-tab-indicator { bottom: -3px; width: 24px; }
  .info-bar { padding: 7px 10px; }
  .info-item { padding: 0 8px; gap: 4px; }
  .info-label, .info-value { font-size: 0.68rem; }
  .content-area { max-height: none; overflow-y: auto; min-height: 0; }
  .adaptive-active .content-area { overflow: hidden; }
  .worldmap-active .content-area { overflow: hidden; }
  .bottom-nav { height: 56px; }
  .nav-btn { font-size: 0.62rem; gap: 2px; }
  .nav-btn-icon { font-size: 1rem; }
  .header-map-title { font-size: 0.85rem; padding: 0 1em; }
}
