
.flip-avatar,
.flip-stage,
.flip-inner,
.flip-face {
  width: 100%;
  height: 100%;
}

.flip-avatar {
  position: relative;
}

.can-flip {
  cursor: pointer;
  outline: none;
}

.can-flip:focus-visible {
  box-shadow: inset 0 0 0 2px rgba(212, 175, 55, 0.78);
}

.can-flip:hover .flip-face img {
  filter: brightness(1.06);
}

.flip-stage {
  perspective: 900px;
}

.flip-inner {
  position: relative;
  transform-style: preserve-3d;
  -webkit-transform-style: preserve-3d;
  will-change: transform;
  transition: transform 0.62s cubic-bezier(0.2, 0.72, 0.25, 1);
}

.is-flipped .flip-inner {
  transform: rotateY(180deg);
}

.flip-face {
  position: absolute;
  inset: 0;
  overflow: hidden;
  backface-visibility: hidden;
  -webkit-backface-visibility: hidden;
  transform-style: preserve-3d;
  -webkit-transform-style: preserve-3d;
  background: rgba(7, 6, 8, 0.96);
}

.flip-front {
  transform: rotateY(0deg) translateZ(0.1px);
}

.flip-back {
  transform: rotateY(180deg) translateZ(0.1px);
}

.flip-face img {
  width: 100%;
  height: 100%;
  display: block;
  object-fit: cover;
  transition: filter 0.2s ease;
}

.flip-placeholder {
  width: 100%;
  height: 100%;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 6px;
  color: rgba(207, 200, 184, 0.28);
  background:
    linear-gradient(145deg, rgba(27, 24, 29, 0.95), rgba(7, 6, 8, 0.98)),
    repeating-linear-gradient(45deg, transparent 0 8px, rgba(207, 200, 184, 0.03) 8px 9px);
}

.flip-placeholder i {
  font-size: 1.2rem;
}

.flip-placeholder span {
  font-family: var(--font-serif);
  font-size: 0.52rem;
  letter-spacing: 0.08em;
  white-space: nowrap;
}

@media (prefers-reduced-motion: reduce) {
  .flip-inner {
    transition-duration: 0.01ms;
  }
}
