
.page-root {
  display: flex;
  flex-direction: column;
  height: 100%;
  overflow: hidden;
  padding: 14px 18px 12px;
  gap: 12px;
  font-size: 1.05rem;
}

.faction-grid {
  flex-shrink: 0;
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 10px;
}

.faction-btn {
  min-height: 86px;
  border: 1px solid rgba(207, 200, 184, 0.18);
  border-radius: 3px;
  background: rgba(0, 0, 0, 0.3);
  color: var(--c-text);
  cursor: pointer;
  display: flex;
  flex-direction: column;
  align-items: flex-start;
  justify-content: center;
  gap: 5px;
  padding: 12px;
  text-align: left;
  position: relative;
  overflow: hidden;
  transition:
    transform 0.2s,
    border-color 0.2s,
    background 0.2s;

  &::before {
    content: '';
    position: absolute;
    inset: 0;
    opacity: 0.18;
    transition: opacity 0.2s;
  }

  &:hover,
  &.active {
    transform: translateY(-1px);
    border-color: currentColor;
    background: rgba(0, 0, 0, 0.42);
  }

  &.active::before,
  &:hover::before {
    opacity: 0.34;
  }

  &.human {
    color: #cfc8b8;
    &::before {
      background: radial-gradient(circle at 85% 20%, rgba(207, 200, 184, 0.45), transparent 48%);
    }
  }
  &.elder {
    color: #d4af37;
    &::before {
      background: radial-gradient(circle at 85% 20%, rgba(212, 175, 55, 0.45), transparent 48%);
    }
  }
  &.old {
    color: #9b7bd3;
    &::before {
      background: radial-gradient(circle at 85% 20%, rgba(155, 123, 211, 0.48), transparent 48%);
    }
  }
  &.outer {
    color: #d88b52;
    &::before {
      background: radial-gradient(circle at 85% 20%, rgba(216, 139, 82, 0.46), transparent 48%);
    }
  }
}

.faction-icon {
  font-size: 1.25rem;
  opacity: 0.9;
  position: relative;
  z-index: 1;
}
.faction-name {
  font-size: 1rem;
  font-family: var(--font-serif);
  letter-spacing: 0.12em;
  position: relative;
  z-index: 1;
}
.faction-count {
  color: var(--c-text-dim);
  font-size: 0.58rem;
  font-family: var(--font-serif);
  position: relative;
  z-index: 1;
}

.roster-panel,
.empty-state {
  flex: 1;
  min-height: 0;
  border-top: 1px solid rgba(38, 38, 38, 0.35);
}

.roster-panel {
  display: flex;
  flex-direction: column;
  gap: 10px;
  padding-top: 10px;
}

.roster-head {
  flex-shrink: 0;
  display: flex;
  justify-content: space-between;
  align-items: flex-end;
  gap: 12px;
}
.roster-kicker {
  display: block;
  color: var(--c-text-dim);
  font-size: 0.58rem;
  letter-spacing: 0.18em;
  font-family: var(--font-serif);
}
.roster-head h2 {
  margin: 2px 0 0;
  color: var(--c-text);
  font-size: 1.1rem;
  font-family: var(--font-serif);
  letter-spacing: 0.12em;
  font-weight: 400;
}
.roster-note {
  color: var(--c-text-dim);
  font-size: 0.68rem;
  line-height: 1.4;
  text-align: right;
  font-family: var(--font-serif);
}

.char-grid {
  flex: 1;
  min-height: 0;
  overflow-y: auto;
  overflow-x: hidden;
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(250px, 1fr));
  align-content: start;
  gap: 10px;
  padding-right: 4px;
  scrollbar-width: thin;
  scrollbar-color: rgba(92, 92, 92, 0.3) transparent;
}
.char-grid::-webkit-scrollbar {
  width: 4px;
}
.char-grid::-webkit-scrollbar-track {
  background: transparent;
}
.char-grid::-webkit-scrollbar-thumb {
  background: rgba(92, 92, 92, 0.3);
  border-radius: 2px;
}

.char-card {
  min-height: 128px;
  display: flex;
  gap: 11px;
  padding: 10px;
  border: 1px solid rgba(207, 200, 184, 0.14);
  border-radius: 3px;
  background:
    linear-gradient(180deg, rgba(13, 12, 14, 0.7), rgba(7, 6, 8, 0.88)),
    radial-gradient(circle at 100% 0%, rgba(207, 200, 184, 0.06), transparent 55%);
  cursor: pointer;
  transition:
    border-color 0.2s,
    transform 0.2s,
    background 0.2s;

  &:hover {
    transform: translateY(-1px);
    background:
      linear-gradient(180deg, rgba(17, 15, 18, 0.82), rgba(8, 7, 9, 0.94)),
      radial-gradient(circle at 100% 0%, rgba(207, 200, 184, 0.11), transparent 55%);
  }

  &.human:hover {
    border-color: rgba(207, 200, 184, 0.42);
  }
  &.elder:hover {
    border-color: rgba(212, 175, 55, 0.45);
  }
  &.old:hover {
    border-color: rgba(155, 123, 211, 0.48);
  }
  &.outer:hover {
    border-color: rgba(216, 139, 82, 0.48);
  }
}

.char-avatar {
  width: 72px;
  height: 96px;
  flex-shrink: 0;
  position: relative;
  padding: 3px;
  border: 1px solid rgba(207, 200, 184, 0.18);
  background: rgba(0, 0, 0, 0.38);
  display: flex;
  align-items: center;
  justify-content: center;

  i {
    position: relative;
    z-index: 2;
    color: rgba(207, 200, 184, 0.22);
    font-size: 1.25rem;
  }
}
.avatar-dash {
  position: absolute;
  inset: 2px;
  border: 1px dashed rgba(207, 200, 184, 0.08);
}
.avatar-img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  position: relative;
  z-index: 3;
}

.char-info {
  flex: 1;
  min-width: 0;
  display: flex;
  flex-direction: column;
  gap: 5px;
}
.char-top {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  gap: 8px;
}
.char-name {
  color: var(--c-text);
  font-size: 1.02rem;
  font-family: var(--font-serif);
  letter-spacing: 0.08em;
  font-weight: 500;
}
.char-rank {
  flex-shrink: 0;
  color: var(--c-gold-dim);
  font-size: 0.56rem;
  border: 1px solid rgba(207, 200, 184, 0.18);
  padding: 2px 5px;
  border-radius: 2px;
  font-family: var(--font-serif);
}
.char-sub {
  color: var(--c-text-dim);
  font-size: 0.62rem;
  font-family: var(--font-serif);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}
.char-card p {
  margin: 0;
  color: var(--c-text);
  font-size: 0.72rem;
  line-height: 1.55;
  font-family: var(--font-serif);
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}
.char-foot {
  margin-top: auto;
  display: flex;
  justify-content: space-between;
  gap: 8px;
  color: var(--c-text-dim);
  font-size: 0.58rem;
  font-family: var(--font-serif);
}
.char-tag {
  color: var(--c-gold);
}

.empty-state,
.empty-msg {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  color: var(--c-text-dim);
  font-family: var(--font-serif);
  font-size: 0.86rem;
  font-style: italic;
}
.empty-msg {
  min-height: 160px;
}

.detail-body {
  display: flex;
  flex-direction: column;
  align-items: center;
}
.dt-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 8px 20px;
  width: 100%;
  margin-bottom: 14px;
}
.dt-row {
  display: flex;
  justify-content: space-between;
  padding: 5px 0;
  border-bottom: 1px solid rgba(38, 38, 38, 0.3);
  gap: 12px;
}
.dt-lbl {
  font-size: 0.85rem;
  color: var(--c-text-dim);
  font-family: var(--font-serif);
  flex-shrink: 0;
}
.dt-val {
  font-size: 0.9rem;
  color: var(--c-text);
  text-align: right;
  font-family: var(--font-serif);
}
.dt-gold {
  color: var(--c-gold);
}
.dt-brainwash {
  color: #8b5a9a;
}
.aff-good {
  color: var(--c-affinity-green);
}
.aff-evil {
  color: var(--c-stamp);
}
.dt-block {
  width: 100%;
  margin-top: 12px;
}
.dt-block-title {
  font-size: 0.85rem;
  color: var(--c-gold-dark);
  border-bottom: 1px solid rgba(38, 38, 38, 0.4);
  padding-bottom: 4px;
  margin-bottom: 8px;
  font-family: var(--font-serif);
  letter-spacing: 0.06em;
}
.dt-block p {
  font-size: 0.88rem;
  color: var(--c-text);
  line-height: 1.7;
  margin: 0;
  font-family: var(--font-serif);
}

@media (max-width: 500px) {
  .page-root {
    padding: 10px 11px 8px;
    gap: 9px;
  }
  .faction-grid {
    gap: 8px;
  }
  .faction-btn {
    min-height: 70px;
    padding: 9px;
  }
  .faction-icon {
    font-size: 1rem;
  }
  .faction-name {
    font-size: 0.88rem;
  }
  .roster-head {
    align-items: flex-start;
    flex-direction: column;
    gap: 4px;
  }
  .roster-note {
    text-align: left;
    font-size: 0.62rem;
  }
  .char-grid {
    grid-template-columns: 1fr;
  }
  .char-avatar {
    width: 58px;
    height: 78px;
  }
  .char-card {
    min-height: 104px;
  }
  .char-name {
    font-size: 0.92rem;
  }
  .char-card p {
    font-size: 0.66rem;
  }
  .dt-grid {
    grid-template-columns: 1fr;
  }
}
