
.map-root {
  position: relative;
  display: flex;
  height: 100%;
  min-height: 0;
  flex-direction: column;
  background: #080a0c;

  &.fullscreen,
  &:fullscreen {
    width: 100%;
    height: 100%;
    max-width: none;
    background: #050608;
  }

  &.fullscreen { position: fixed; inset: 0; z-index: 9999; }
  &:fullscreen { position: fixed; inset: 0; }
}

.map-stage-wrap {
  display: flex;
  flex: 1;
  min-height: 0;
  align-items: center;
  justify-content: center;
  overflow: hidden;
  background: #050608;
  cursor: default;
  touch-action: none;
  user-select: none;

  &.zoomed { cursor: default; }
  &.grabbing { cursor: default; }
  &.crosshair { cursor: crosshair; }
}

.map-frame {
  position: relative;
  container-type: inline-size;
  height: 100%;
  max-width: 100%;
  max-height: 100%;
  aspect-ratio: 16 / 9;
  margin: 0;
  overflow: hidden;
  border: 1px solid rgba(207, 200, 184, 0.16);
  background: #030405;
  box-shadow: inset 0 0 32px rgba(0, 0, 0, 0.5), 0 8px 28px rgba(0, 0, 0, 0.45);

  &::after {
    position: absolute;
    z-index: 30;
    inset: 0;
    box-shadow: inset 0 0 42px rgba(0, 0, 0, 0.42), inset 0 0 0 1px rgba(255, 255, 255, 0.03);
    content: '';
    pointer-events: none;
  }
}

.map-content {
  position: absolute;
  top: 0;
  left: 0;
  transform-origin: 0 0;
}

.map-image {
  display: block;
  width: 100%;
  height: 100%;
  object-fit: contain;
  background: #030405;
  pointer-events: none;
  user-select: none;
  -webkit-user-drag: none;
}

.map-region-layer,
.map-marker-layer {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  pointer-events: none;
}

.faction-region {
  pointer-events: none;
  stroke-width: 0.28;
  vector-effect: non-scaling-stroke;
  transition: fill-opacity 0.2s ease, stroke-width 0.2s ease;

  &.selectable { pointer-events: auto; cursor: pointer; }
  &.selected { stroke: #f2e5bd; stroke-width: 0.7; }
}

.draft-region-line {
  fill: rgba(198, 166, 100, 0.12);
  stroke: #f2d896;
  stroke-width: 0.45;
  stroke-dasharray: 1.2 0.8;
  vector-effect: non-scaling-stroke;
}

.draft-vertex {
  fill: #f5e6b8;
  stroke: #1b1510;
  stroke-width: 0.2;
  vector-effect: non-scaling-stroke;
}

.map-marker {
  --marker-color: #c9a94e;
  position: absolute;
  width: var(--marker-hit-size, 14px);
  height: var(--marker-hit-size, 14px);
  padding: 0;
  border: 0;
  background: transparent;
  color: var(--marker-color);
  transform: translate(-50%, -50%);
  pointer-events: auto;
}

.fixed-marker {
  cursor: pointer;
  pointer-events: auto;
}

.fixed-marker {
  animation: location-marker-reveal 0.34s cubic-bezier(0.2, 0.9, 0.25, 1.2) both;

  .marker-dot {
    position: absolute;
    top: 50%;
    left: 50%;
    display: block;
    box-sizing: border-box;
    width: var(--marker-dot-size, 4px);
    height: var(--marker-dot-size, 4px);
    border: var(--marker-border-size, 1px) solid rgba(255, 247, 224, 0.94);
    border-radius: 50%;
    background: var(--marker-color);
    box-shadow:
      0 0 0 var(--marker-border-size, 1px) rgba(7, 8, 9, 0.78),
      0 0 var(--marker-glow-size, 3px) var(--marker-color);
    transform: translate(-50%, -50%);
    transform-origin: center;
    transition: transform 0.16s ease, box-shadow 0.16s ease, filter 0.16s ease;
  }

  .marker-label {
    position: absolute;
    top: 50%;
    left: 50%;
    color: #f1e7c9;
    font-size: var(--marker-label-size, 5px);
    font-weight: 500;
    line-height: 1.05;
    white-space: nowrap;
    text-shadow: 0 0.08cqw 0.16cqw #000, 0 0 0.24cqw #000;
    transform: translate(-50%, var(--marker-label-gap, 3px));
    pointer-events: none;
    transition: color 0.16s ease, text-shadow 0.16s ease;

    &.vertical-left {
      top: 50%;
      left: 50%;
      line-height: 1;
      text-orientation: upright;
      transform: translate(calc(-100% - var(--marker-label-gap, 3px)), -50%);
      writing-mode: vertical-rl;
    }
  }

  &:hover,
  &:focus-visible {
    z-index: 12;

    .marker-dot {
      box-shadow:
        0 0 0 var(--marker-border-size, 1px) rgba(255, 247, 224, 0.9),
        0 0 var(--marker-hover-glow-size, 6px) var(--marker-color);
      filter: brightness(1.22) saturate(1.12);
      transform: translate(-50%, -50%) scale(1.4);
    }

    .marker-label {
      color: #fff3d7;
      text-shadow: 0 1px 2px #000, 0 0 5px var(--marker-color);
    }
  }
}

.location-detail {
  position: absolute;
  z-index: 35;
  bottom: clamp(7px, 1.5cqw, 14px);
  left: clamp(7px, 1.5cqw, 14px);
  box-sizing: border-box;
  width: min(35cqw, 292px);
  min-width: 178px;
  padding: clamp(9px, 1.35cqw, 14px);
  padding-right: clamp(30px, 3.8cqw, 38px);
  border: 1px solid rgba(212, 203, 179, 0.26);
  border-radius: 6px;
  background: rgba(8, 9, 11, 0.92);
  box-shadow: 0 8px 24px rgba(0, 0, 0, 0.48);
  color: #e8dfcc;
  font-family: var(--font-ui);
  backdrop-filter: blur(9px);

  h3 {
    margin: 4px 0 6px;
    color: #f1e5c9;
    font-size: clamp(0.72rem, 1.8cqw, 0.98rem);
    font-weight: 500;
    line-height: 1.2;
  }

  p {
    margin: 0;
    color: #c6beae;
    font-size: clamp(0.56rem, 1.15cqw, 0.7rem);
    line-height: 1.65;
  }
}

.location-detail-meta {
  display: flex;
  flex-wrap: wrap;
  gap: 4px 9px;
  color: #bca57a;
  font-size: clamp(0.48rem, 0.92cqw, 0.58rem);

  span + span::before {
    margin-right: 9px;
    color: rgba(188, 165, 122, 0.5);
    content: '·';
  }
}

.location-detail-close {
  position: absolute;
  top: 6px;
  right: 6px;
  display: grid;
  width: 24px;
  height: 24px;
  padding: 0;
  border: 0;
  border-radius: 3px;
  background: transparent;
  color: #a9a194;
  cursor: pointer;
  place-items: center;

  &:hover { background: rgba(255, 255, 255, 0.07); color: #efe3ca; }
}

.current-location-marker {
  position: absolute;
  z-index: 8;
  width: var(--current-marker-size, 16px);
  height: var(--current-marker-size, 16px);
  padding: 0;
  border: 0;
  border-radius: 50%;
  outline: none;
  background: transparent;
  transform: translate(-50%, -50%);
  cursor: pointer;
  pointer-events: auto;

  &:hover .current-location-ring,
  &:focus-visible .current-location-ring {
    animation-play-state: paused;
    opacity: 1;
    transform: scale(1);
  }

  &:hover .current-location-glyph,
  &:focus-visible .current-location-glyph {
    animation-play-state: paused;
    filter: brightness(1.28) drop-shadow(0 0 5px rgba(238, 73, 73, 0.98));
    transform: translate(-50%, -50%) scale(1.55);
  }
}

.current-location-ring {
  position: absolute;
  inset: 12%;
  border: var(--marker-border-size, 1px) solid rgba(229, 79, 79, 0.82);
  border-radius: 50%;
  animation: location-pulse 1.8s ease-out infinite;
  opacity: 0.45;
  transform: scale(0.5);
  transition: opacity 0.16s ease, transform 0.16s ease;
}

.current-location-glyph {
  position: absolute;
  top: 50%;
  left: 50%;
  width: var(--player-glyph-width, 7px);
  height: var(--player-glyph-height, 10px);
  transform: translate(-50%, -50%);
  animation: player-glyph-blink 1.35s ease-in-out infinite;
  filter: drop-shadow(0 0 2px rgba(224, 68, 68, 0.9));
  transition: transform 0.16s ease, filter 0.16s ease;
}

.current-location-head {
  position: absolute;
  top: 0;
  left: 50%;
  width: var(--player-head-size, 3px);
  height: var(--player-head-size, 3px);
  border-radius: 50%;
  background: #ff6a6a;
  transform: translateX(-50%);
}

.current-location-body {
  position: absolute;
  top: 38%;
  left: 50%;
  width: 0;
  height: 0;
  border-top: var(--player-body-height, 5px) solid #e04444;
  border-right: var(--player-body-half, 3px) solid transparent;
  border-left: var(--player-body-half, 3px) solid transparent;
  transform: translateX(-50%);
}

.current-location-label {
  position: absolute;
  top: 50%;
  left: 50%;
  padding: 0;
  color: #fff0d2;
  font-family: var(--font-ui);
  font-size: var(--current-label-size, 0.5rem);
  font-weight: 600;
  line-height: 1;
  text-shadow: 0 1px 2px #000, 0 0 5px rgba(218, 61, 61, 0.92);
  white-space: nowrap;
  transform: translate(-50%, calc(-100% - var(--current-label-gap, 10px)));
  pointer-events: none;
}

.sample-marker {
  position: absolute;
  z-index: 10;
  width: 8px;
  height: 8px;
  transform: translate(-50%, -50%);
  pointer-events: none;

  &::before,
  &::after { position: absolute; background: #f4dc99; content: ''; }
  &::before { top: 50%; left: -3px; width: 14px; height: 1px; }
  &::after { top: -3px; left: 50%; width: 1px; height: 14px; }

  span {
    position: absolute;
    inset: 2px;
    border: 1px solid #f4dc99;
    border-radius: 50%;
    background: rgba(20, 15, 8, 0.75);
  }
}

.map-error {
  position: absolute;
  z-index: 40;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(5, 6, 8, 0.86);
  color: var(--c-text-dim);
  font-family: var(--font-ui);
  font-size: 0.72rem;
}

.map-controls {
  position: absolute;
  z-index: 50;
  top: 10px;
  right: 10px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
}

.map-control-btn,
.developer-header button,
.coordinate-readout button,
.vertex-status button {
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 0;
  border: 1px solid rgba(180, 180, 190, 0.22);
  border-radius: 2px;
  background: rgba(10, 10, 10, 0.86);
  color: var(--c-gold);
  cursor: pointer;
}

.map-control-btn {
  width: 28px;
  height: 28px;
  font-size: 0.72rem;

  &:hover,
  &.active { border-color: rgba(211, 77, 77, 0.6); background: rgba(97, 27, 27, 0.86); color: #f1d8ad; }
  &.dirty::after { position: absolute; width: 5px; height: 5px; margin: -20px 0 0 20px; border-radius: 50%; background: #d64a4a; content: ''; }
}

.zoom-level {
  min-width: 32px;
  padding: 1px 4px;
  border: 1px solid rgba(180, 180, 190, 0.16);
  border-radius: 2px;
  background: rgba(0, 0, 0, 0.58);
  color: var(--c-text-dim);
  font-family: var(--font-ui);
  font-size: 0.5rem;
  line-height: 1.5;
  text-align: center;
}

.developer-panel {
  position: absolute;
  z-index: 45;
  top: 0;
  left: 0;
  display: flex;
  width: min(292px, calc(100% - 64px));
  max-height: calc(100% - 20px);
  flex-direction: column;
  overflow: auto;
  border: 1px solid rgba(207, 200, 184, 0.24);
  border-radius: 4px;
  background: rgba(7, 8, 11, 0.95);
  box-shadow: 0 12px 32px rgba(0, 0, 0, 0.55);
  color: var(--c-text);
  font-family: var(--font-ui);
  backdrop-filter: blur(10px);
  touch-action: pan-y;

  &.dragging { cursor: grabbing; }
}

.developer-header {
  position: sticky;
  z-index: 3;
  top: 0;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 9px 10px;
  border-bottom: 1px solid rgba(207, 200, 184, 0.12);
  background: rgba(9, 10, 13, 0.98);
  cursor: grab;
  touch-action: none;

  strong { display: block; font-size: 0.78rem; font-weight: 500; }
  span { display: block; margin-top: 2px; color: var(--c-text-dim); font-size: 0.55rem; }
  span.changed { color: #d79571; }
  button { width: 25px; height: 25px; }
}

.tool-segments {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 1px;
  padding: 8px 10px;

  button {
    height: 30px;
    border: 1px solid rgba(207, 200, 184, 0.14);
    background: rgba(255, 255, 255, 0.025);
    color: var(--c-text-dim);
    cursor: pointer;

    &:first-child { border-radius: 3px 0 0 3px; }
    &:last-child { border-radius: 0 3px 3px 0; }
    &.active { border-color: rgba(179, 62, 62, 0.56); background: rgba(126, 35, 35, 0.32); color: #efd9b8; }
  }
}

.developer-section {
  padding: 8px 10px;
  border-top: 1px solid rgba(207, 200, 184, 0.08);
}

.section-title {
  margin-bottom: 7px;
  color: #d8cbb3;
  font-size: 0.66rem;
  font-weight: 500;
}

.section-note {
  margin: 5px 0;
  color: var(--c-text-dim);
  font-size: 0.55rem;
  line-height: 1.5;
}

.match-row,
.coordinate-readout,
.vertex-status,
.faction-row,
.toggle-row {
  display: flex;
  align-items: center;
}

.match-row {
  justify-content: space-between;
  gap: 8px;
  font-size: 0.61rem;

  span { overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
  b { flex-shrink: 0; color: #c69c72; font-size: 0.52rem; font-weight: 400; }
}

.current-match code,
.coordinate-readout code {
  color: #d8bd80;
  font-size: 0.57rem;
}

.coordinate-readout {
  min-height: 28px;
  justify-content: space-between;
  gap: 8px;
  padding: 4px 6px;
  border: 1px solid rgba(207, 200, 184, 0.12);
  background: rgba(0, 0, 0, 0.24);
  font-size: 0.58rem;

  button { width: 24px; height: 24px; }
}

.editor-form {
  display: flex;
  flex-direction: column;
  gap: 6px;

  > .section-title { margin-bottom: 1px; }
  label { display: flex; flex-direction: column; gap: 3px; }
  label > span { color: var(--c-text-dim); font-size: 0.54rem; }
  input,
  select,
  textarea {
    box-sizing: border-box;
    width: 100%;
    min-width: 0;
    border: 1px solid rgba(207, 200, 184, 0.16);
    border-radius: 2px;
    outline: none;
    background: rgba(0, 0, 0, 0.26);
    color: var(--c-text);
    font: inherit;
    font-size: 0.62rem;
  }
  input,
  select { height: 28px; padding: 3px 6px; }
  input[type='color'] { padding: 2px; }
  input[type='range'] { padding: 0; accent-color: #ad4444; }
  textarea { resize: vertical; padding: 5px 6px; }
  input:focus,
  select:focus,
  textarea:focus { border-color: rgba(198, 166, 100, 0.48); }
}

.form-grid { display: grid; grid-template-columns: 1fr 72px; gap: 6px; }
.form-grid.coordinates { grid-template-columns: 1fr 1fr; }

.editor-form .optional-faction-toggle {
  display: flex;
  flex-direction: row;
  align-items: center;
  gap: 6px;
  min-height: 25px;

  input { width: auto; height: auto; accent-color: #a84242; }
  span { color: #c9bda8; }
}

.form-actions {
  display: flex;
  justify-content: flex-end;
  gap: 6px;

  button {
    min-height: 28px;
    padding: 4px 9px;
    border: 1px solid rgba(207, 200, 184, 0.18);
    border-radius: 2px;
    background: rgba(255, 255, 255, 0.035);
    color: var(--c-text-dim);
    font: inherit;
    font-size: 0.59rem;
    cursor: pointer;
  }
  button.primary { border-color: rgba(198, 166, 100, 0.34); color: #e6d2aa; }
  button.danger { margin-right: auto; color: #c97878; }
  button:disabled { cursor: default; opacity: 0.35; }
}

.vertex-status {
  gap: 5px;
  color: var(--c-text-dim);
  font-size: 0.56rem;

  span { margin-right: auto; }
  button { width: 24px; height: 24px; }
}

.layer-settings { display: grid; grid-template-columns: repeat(3, 1fr); gap: 5px; }
.layer-settings .section-title { grid-column: 1 / -1; margin: 0; }
.toggle-row { gap: 4px; font-size: 0.54rem; white-space: nowrap; }
.toggle-row input,
.faction-row input[type='checkbox'] { accent-color: #a84242; }

.faction-row {
  grid-column: 1 / -1;
  gap: 6px;
  min-width: 0;
  font-size: 0.57rem;

  input[type='color'] { width: 24px; height: 20px; padding: 1px; border: 0; background: transparent; }
  span { overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
}

.developer-footer {
  position: sticky;
  z-index: 3;
  bottom: 0;
  display: flex;
  justify-content: flex-end;
  gap: 6px;
  padding: 9px 10px;
  border-top: 1px solid rgba(207, 200, 184, 0.12);
  background: rgba(9, 10, 13, 0.98);

  button {
    min-height: 30px;
    padding: 4px 10px;
    border: 1px solid rgba(207, 200, 184, 0.18);
    border-radius: 2px;
    background: rgba(255, 255, 255, 0.035);
    color: var(--c-text-dim);
    font: inherit;
    font-size: 0.6rem;
    cursor: pointer;
  }
  button.save { border-color: rgba(176, 63, 63, 0.55); background: rgba(128, 35, 35, 0.3); color: #ead4b4; }
  button:disabled { cursor: default; opacity: 0.35; }
}

@keyframes location-pulse {
  0% { opacity: 0.62; transform: scale(0.48); }
  78%, 100% { opacity: 0; transform: scale(1.18); }
}

@keyframes player-glyph-blink {
  0%, 100% { opacity: 0.78; filter: brightness(0.92) drop-shadow(0 0 1px rgba(216, 61, 61, 0.72)); }
  50% { opacity: 1; filter: brightness(1.24) drop-shadow(0 0 5px rgba(238, 73, 73, 0.98)); }
}

@keyframes location-marker-reveal {
  0% { opacity: 0; filter: brightness(1.8); transform: translate(-50%, -50%) scale(0.35); }
  72% { opacity: 1; filter: brightness(1.18); transform: translate(-50%, -50%) scale(1.12); }
  100% { opacity: 1; filter: brightness(1); transform: translate(-50%, -50%) scale(1); }
}

@media (max-width: 500px) {
  .map-controls { top: 6px; right: 6px; gap: 3px; }
  .map-control-btn { width: 30px; height: 30px; }
  .developer-panel { width: min(260px, calc(100% - 48px)); max-height: calc(100% - 12px); }
  .developer-header { padding: 7px 8px; }
  .developer-section { padding: 7px 8px; }
  .tool-segments { padding: 6px 8px; }
  .current-location-label { max-width: 86px; }
}
